#include <iostream>
using namespace std;
int main() {
    int H1, H2, H3, H4;
    cin >> H1 >> H2 >> H3 >> H4;

    int ans = H2;
    int d = H1 - H2;
    if (d < 0) d = -d;
    int mnd = d;

    d = H1 - H3;
    if (d < 0) d = -d;
    if (d < mnd || (d == mnd && H3 < ans))
        ans = H3, mnd = d;

    d = H1 - H4;
    if (d < 0) d = -d;
    if (d < mnd || (d == mnd && H4 < ans))
        ans = H4;

    cout << ans << endl;
    return 0;
}

